mapper.select:
SELECT id, job_id, job_name, job_type, executor_address, executor_handler,
       params, status, retry_times, fail_reason, start_time, end_time,
       cost_time, result, host_address, create_time
FROM schedule_job_log


        AND job_id = #{jobId}


        AND status = #{status}


        AND create_time >= #{startTime}


        AND create_time <= #{endTime}


ORDER BY create_time DESC
LIMIT 100
